// // 这个模块管理数字系统中的读写操作状态。它包括异步复位、时钟信号、写请求和读请求输入，并输出当前的写状态（wr_sta）和读状态（rd_sta）。当写请求被发出时，模块会相应地设置写状态。读状态在读请求待处理时被激活，但仅在没有写操作活动的情况下。这确保了只有在安全时才能进行读取，防止读写操作之间的冲突。
module top_module(nrst, clk, wr_req, rd_req, wr_sta, rd_sta);input nrst;
    input clk;
    input wr_req;
    input rd_req;
    output wr_sta;    // 处于写状态
    output rd_sta;    // 处于读状态

    reg wr_sta; 
    reg rd_pend;    // 读请求pending信号

    // 写状态转换
    always @(posedge clk or negedge nrst) begin
        if (~nrst) begin
            wr_sta <= 1'b0;
        end else begin
            wr_sta <= wr_req;
        end
    end

    // 读pending状态转换
    always @(posedge clk or negedge nrst) begin
        if (~nrst) begin
            rd_pend <= 1'b0;
        end else if (rd_req) begin
            rd_pend <= 1'b1;
        end else if (rd_sta) begin
            rd_pend <= 1'b0;
        end
    end

    // 当写状态无效且读pending时才可读
    assign rd_sta = rd_pend & ~wr_sta;
endmodule
